import { Component, Inject } from '@angular/core';
import { MAT_DIALOG_DATA } from '@angular/material/dialog';
import { ExportDailyWeather, Weather } from '../../angular-model/weather';

@Component({
  selector: 'app-app-modal',
  templateUrl: './app-modal.component.html',
  styleUrls: ['./app-modal.component.css']
})
export class AppModalComponent {
  constructor(@Inject(MAT_DIALOG_DATA) public data: { daily: ExportDailyWeather, weatherData: Weather[] }) {
    debugger;
    console.log('Daily Data:', data.daily);
    console.log('Weather Data:', data.weatherData);
  }
}
<h2 mat-dialog-title>Dialog with elements</h2>
<mat-dialog-content>This dialog showcases the title, close, content and actions elements.</mat-dialog-content>
<mat-dialog-actions>
  <button mat-button mat-dialog-close>Close</button>
</mat-dialog-actions>
